<?php
include __DIR__ . '/../includes/init.php';
session_start();

$model = new Model();

// Load NTA list from static cache (generated by cron) instead of live Airtable API
$ntaCacheFile = __DIR__ . '/nta_list_cache.json';
if (!isset($_SESSION['ntas']) || !$_SESSION['ntas']) {
    if (file_exists($ntaCacheFile)) {
        $_SESSION['ntas'] = json_decode(file_get_contents($ntaCacheFile), true);
    } else {
        // Fallback: live Airtable API (slow, ~3s)
        $_SESSION['ntas'] = AirtableCovidModel::getNtaList();
    }
}
$ntaName = mapIncomingRequest($_GET);

$cards = $ntaName ? $model->getCovidPrj($ntaName) : null;

header('content-type: text/html; charset=UTF-8');
//echo json_encode($cards);
echo "<!-- Debug: NTA='{$ntaName}' Count=" . count((array)$cards) . " -->";
echo "<span id='response-nta-name' style='display:none;'>{$ntaName}</span>";
viewResponse($cards);



function mapIncomingRequest($rr)
{
	if ((!isset($rr['nta']) || !$rr['nta']) && (!isset($rr['address']) || !$rr['address']))
		return null;
	if (isset($rr['nta']) && is_array($rr['nta']))
		$rr['nta'] = array_shift($rr['nta']);
	if (isset($rr['address']) && $rr['address'])
	{
		$gcNta = Geoclient::getNtaCode($rr['address']);
		if ($gcNta)
			$rr['nta'] = $gcNta;
	}	
	
	return $_SESSION['ntas'][$rr['nta']]['name'];
}


