function viewResponse($cc)
{
	if ($cc === null)
	{
		echo 'It is not possible to detect neighborhood zone by entered address. Please try again';
		die();
	}
	if (!$cc)
	{
		echo 'Sadly nothing found. Please try another neighbourhood zone';
		die();
	}
	?>
	<div>
	  <?php foreach ($cc as $c)
	  {
			viewGroup($c);
	  }
	  ?>
	</div>
	
	<?php
}


