class grViewer
{
	var $dd;
	function __construct($gr)
	{
		$this->dd = $gr;
		// DB fields are already flattened, but some might be JSON encoded.
		// For simplicity, we might need to assume fields are available directly.
		// However, the original code looked for 'Group Name' etc. which are Airtable keys.
		// In database, we probably saved them as 'Group Name' etc?
		// Wait, cacheupdate.php used normRec(['id' => $aCard['id']] + $aCard['fields'], 'covid_prj');
		// And normRec uses specific keys like 'name', 'description'.
		// So $gr will have 'name', 'description' etc directly.
		
		// Map DB columns back to what grViewer expects or update grViewer.
		// Let's update grViewer usage.
		$this->dd['Group Name'] = $this->dd['name'];
		$this->dd['Short Description'] = $this->dd['description'];
		$this->dd['Group Email'] = $this->dd['email_pub'] ?? ''; // cacheupdate maps email_pub
		$this->dd['Website'] = $this->dd['url'];
		
		// Remap for compatibility
		$this->dd['name'] = $this->dd['Group Name'] ?? '';
		$this->dd['description'] = $this->dd['Short Description'] ?? '';
		$this->dd['email'] = $this->dd['Group Email'] ?? '';
		$this->dd['website'] = $this->dd['website'] ?? '';
		$this->dd['Facebook'] = $this->dd['facebook'] ?? null;
		$this->dd['Instagram'] = $this->dd['instagram'] ?? null;
		$this->dd['X'] = $this->dd['twitter'] ?? null;

		if (isset($this->dd['geo_scope']) && is_string($this->dd['geo_scope'])) {
			$this->dd['Geographical Scope'] = json_decode($this->dd['geo_scope'], true);
		} else {
			$this->dd['Geographical Scope'] = $this->dd['Geographical Scope'] ?? [];
		}

		if (isset($this->dd['nta']) && is_string($this->dd['nta'])) {
			$this->dd['Neighborhoods'] = json_decode($this->dd['nta'], true);
		} else {
			$this->dd['Neighborhoods'] = $this->dd['Neighborhoods'] ?? [];
		}

		if (isset($this->dd['images']) && is_string($this->dd['images'])) {
			$this->dd['Cover Image'] = json_decode($this->dd['images'], true);
		} else {
			$this->dd['Cover Image'] = $this->dd['Cover Image'] ?? [];
		}
	}
	
	function v($f)
	{
		$d = $this->dd[$f] ?? '';
		switch ($f)
		{
			case 'Facebook':
				$d = str_replace('@', 'https://www.facebook.com/', $d);
				break;
			case 'Instagram':
				$d = str_replace('@', 'https://www.instagram.com/', $d);
				break;
			case 'X':
				$d = str_replace('@', 'https://twitter.com/', $d);
				break;
			case 'website':
				$d = preg_match('~http~si', $d) ? $d : "//{$d}";
				break;
		}
		echo $d;
	}
	
	function images()
	{
		$rr = [];
		foreach ((array)($this->dd['Cover Image'] ?? []) as $i)
			$rr[] = ['url' => $i['url'], 'icon' => $i['thumbnails']['small']['url'], 'bigIcon' => $i['thumbnails']['large']['url']];
		return $rr;
	}
	
	function ntas()
	{
		return (array)$this->dd['Neighborhoods'];
	}
}